import sys

class Solution:
    def myPow(self, x: float, n: int) -> float:
        if n < 0:
            x = 1 / x
            n = -n
        res = 1
        while n > 0:
            if n & 1:
                res *= x
            x *= x
            n >>= 1
        return res

if __name__ == '__main__':
    x = float(sys.stdin.readline().strip())
    n = int(sys.stdin.readline().strip())
    sol = Solution()
    ans = sol.myPow(x, n)
    print(f'{ans:.10f}')

