#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    double myPow(double x, int n) {
        if (n < 0) {
            x = 1 / x;
            n = -n;
        }
        double res = 1;
        while (n > 0) {
            if (n & 1) {
                res *= x;
            }
            x *= x;
            n >>= 1;
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    double x;
    cin >> x;
    int n;
    cin >> n;
    Solution sol;
    double ans = sol.myPow(x, n);
    cout << fixed << setprecision(10) << ans << '\n';
    return 0;
}
